def solve_quadratic_equation(a, b, c): #一元二次方程
    if a==0:
        return float('nan')
    x1 = (-b+sqrt(b**2-4*a*c))/(2*a)
    x2 = (-b-sqrt(b**2-4*a*c))/(2*a)
    return [x1, x2]
