def diff(fx: list): #求导
    if len(fx)==0:
        return float('nan')
    elif len(fx)==1:
        return 0
    n = len(fx)
    fx.reverse()
    fpx = []
    for i in range(n-1, 0, -1):
        fpx.append(i*fx[i])
    return fpx
